+        const index = self.count;
+        self.count += 1;
+
+        if (self.count == self.parties) {
+            // Last thread - release all
+            self.count = 0;
+            self.generation += 1;
+            self.cond.broadcast();
+            return index;
+        }
+
+        // Wait for release
+        if (timeout_us < 0) {
+            while (gen == self.generation and !self.broken) {
+                self.cond.wait(&self.mutex);
+            }
+        } else {
+            const start = std.time.nanoTimestamp();
+            const timeout_ns = timeout_us * 1000;
+
+            while (gen == self.generation and !self.broken) {
+                const elapsed = std.time.nanoTimestamp() - start;
+                if (elapsed >= timeout_ns) {
+                    self.broken = true;
+                    self.cond.broadcast();
+                    return error.Timeout;
+                }
+
+                const remaining: u64 = @intCast(timeout_ns - elapsed);
+                _ = self.cond.timedWait(&self.mutex, remaining);
+            }
+        }
+
+        if (self.broken) {
+            return error.BrokenBarrier;
+        }
+
+        return index;
+    }
+
+    pub fn reset(self: *Self) void {
+        self.mutex.lock();
+        self.count = 0;
+        self.generation += 1;
+        self.broken = false;
+        self.cond.broadcast();
+        self.mutex.unlock();
+    }
+
+    pub fn abort(self: *Self) void {
+        self.mutex.lock();
+        self.broken = true;
+        self.cond.broadcast();
+        self.mutex.unlock();
+    }
+
+    pub fn getParties(self: *Self) usize {
+        return self.parties;
+    }
+
+    pub fn getWaiting(self: *Self) usize {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+        return self.count;
+    }
+
+    pub fn isBroken(self: *Self) bool {
+        self.mutex.lock();
+        defer self.mutex.unlock();
+        return self.broken;
+    }
+};
+
+// ============================================================================
+// Initialization
+// ============================================================================
+
+var initialized = false;
+
+/// Initialize thread module
+pub fn init() void {
+    if (initialized) return;
+    initialized = true;
+}
+
+// ============================================================================
+// At Fork Handling
+// ============================================================================
+
+/// Reinitialize lock after fork
+pub fn atForkReinit(lock: *Lock) void {
+    lock.* = .{};
+}
